import re
import operator
from functools import partial

from collections import defaultdict
from typing import Iterable, Mapping, Sequence, Dict, Any, List
from typing import Callable, List, Dict

def select_fields(records: Iterable[Mapping[str, Any]], fields: Sequence[str]) -> List[Dict[str, Any]]:
    """
    Return a list of dictionaries containing only the specified fields for each record.

    - records: iterable of dictionaries (data records)
    - fields: list/sequence of field names (strings) to select

    Missing fields in a record are omitted from that record's result.
    Non-dict records are ignored.
    """
    result: List[Dict[str, Any]] = []
    for record in records or []:
        if not isinstance(record, dict):
            continue
        selected = {field: record[field] for field in fields if field in record}
        result.append(selected)
    return result

def filter_data(records: List[Dict[str, Any]], condition: Callable[[Dict[str, Any]], bool]) -> List[Dict[str, Any]]:
    """
    Return a list of records that satisfy the provided condition.

    - records: list of dictionaries (data records)
    - condition: callable that accepts a record and returns True if it should be included

    Non-dict items in records are ignored.
    """
    if condition is None or not callable(condition):
        raise TypeError("condition must be a callable taking a record and returning bool")

    filtered: List[Dict[str, Any]] = []
    for record in records or []:
        if not isinstance(record, dict):
            continue
        if condition(record):
            filtered.append(record)
    return filtered


# --- SQL-like query execution ---

# Tokenizer for WHERE clause
_TOKEN_RE = re.compile(
    r"""
    \s*(?:
        (?P<number>[-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?) |
        (?P<string>'([^'\\]|\\.)*'|"([^"\\]|\\.)*") |
        (?P<op><=|>=|<>|!=|=|<|>) |
        (?P<lparen>\() |
        (?P<rparen>\)) |
        (?P<comma>,) |
        (?P<word>[A-Za-z_][A-Za-z0-9_]*)
    )
    """,
    re.VERBOSE,
)

def _unescape_string(s: str) -> str:
    if not s:
        return s
    quote = s[0]
    if quote not in ("'", '"') or s[-1] != quote:
        raise ValueError("Invalid string literal")
    body = s[1:-1]

    # Handle common escapes
    escapes = {
        r"\\": "\\",
        r"\'": "'",
        r'\"': '"',
        r"\n": "\n",
        r"\r": "\r",
        r"\t": "\t",
        r"\b": "\b",
        r"\f": "\f",
        r"\v": "\v",
        r"\0": "\0",
    }
    # Replace escapes
    i = 0
    out = []
    while i < len(body):
        if body[i] == "\\" and i + 1 < len(body):
            seq = body[i : i + 2]
            if seq in escapes:
                out.append(escapes[seq])
                i += 2
                continue
        out.append(body[i])
        i += 1
    return "".join(out)

def _tokenize_where(where_str: str):
    tokens = []
    pos = 0
    length = len(where_str)
    while pos < length:
        m = _TOKEN_RE.match(where_str, pos)
        if not m:
            raise ValueError(f"Unexpected token near: {where_str[pos:pos+20]!r}")
        pos = m.end()
        kind = m.lastgroup
        if kind == "number":
            tokens.append(("NUMBER", m.group(kind), m.group(kind)))
        elif kind == "string":
            tokens.append(("STRING", m.group(kind), m.group(kind)))
        elif kind == "op":
            tokens.append(("OP", m.group(kind), m.group(kind)))
        elif kind == "lparen":
            tokens.append(("LPAREN", "(", "("))
        elif kind == "rparen":
            tokens.append(("RPAREN", ")", ")"))
        elif kind == "comma":
            tokens.append(("COMMA", ",", ","))
        elif kind == "word":
            word = m.group(kind)
            tokens.append(("WORD", word.upper(), word))
        else:
            raise ValueError("Tokenizer error")
    # Combine NOT + IN into NOT IN for easier parsing
    combined = []
    i = 0
    while i < len(tokens):
        t = tokens[i]
        if (
            i + 1 < len(tokens)
            and t[0] == "WORD"
            and t[1] == "NOT"
            and tokens[i + 1][0] == "WORD"
            and tokens[i + 1][1] == "IN"
        ):
            combined.append(("WORD", "NOT IN", "NOT IN"))
            i += 2
        else:
            combined.append(t)
            i += 1
    return combined

class _TokenStream:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        if self.pos >= len(self.tokens):
            return ("EOF", "EOF", None)
        return self.tokens[self.pos]

    def next(self):
        tok = self.peek()
        if self.pos < len(self.tokens):
            self.pos += 1
        return tok

    def match_word(self, word: str) -> bool:
        tok = self.peek()
        if tok[0] == "WORD" and tok[1] == word:
            self.next()
            return True
        return False

    def match_type(self, typ: str) -> bool:
        tok = self.peek()
        if tok[0] == typ:
            self.next()
            return True
        return False

    def expect(self, typ: str, value: str = None):
        tok = self.peek()
        if tok[0] != typ or (value is not None and tok[1] != value):
            raise ValueError(f"Expected {typ} {value or ''} but got {tok}")
        return self.next()

def _parse_identifier(ts: _TokenStream) -> str:
    tok = ts.peek()
    if tok[0] == "WORD":
        ts.next()
        return tok[2]  # original case
    raise ValueError("Identifier expected in predicate")

def _parse_value(ts: _TokenStream):
    tok = ts.peek()
    if tok[0] == "NUMBER":
        ts.next()
        text = tok[2]
        if any(c in text for c in ".eE"):
            try:
                return float(text)
            except ValueError:
                raise ValueError(f"Invalid number literal: {text}")
        try:
            return int(text)
        except ValueError:
            raise ValueError(f"Invalid integer literal: {text}")
    elif tok[0] == "STRING":
        ts.next()
        return _unescape_string(tok[2])
    elif tok[0] == "WORD":
        if tok[1] == "TRUE":
            ts.next()
            return True
        if tok[1] == "FALSE":
            ts.next()
            return False
        if tok[1] == "NULL":
            ts.next()
            return None
        # Unquoted bare words are not allowed as values (likely a column name)
        raise ValueError(f"Unexpected bare identifier as value: {tok[2]!r}")
    else:
        raise ValueError(f"Unexpected token in value: {tok}")

def _parse_value_list(ts: _TokenStream):
    values = []
    ts.expect("LPAREN", "(")
    # Empty list allowed?
    first = True
    while True:
        if ts.match_type("RPAREN"):
            break
        if not first:
            ts.expect("COMMA", ",")
        val = _parse_value(ts)
        values.append(val)
        first = False
        if ts.match_type("RPAREN"):
            break
    return values

def _like_to_regex(pattern: str) -> re.Pattern:
    # Convert SQL LIKE pattern (% -> .*, _ -> .)
    # Escape regex metacharacters first
    regex = []
    i = 0
    while i < len(pattern):
        c = pattern[i]
        if c == "%":
            regex.append(".*")
        elif c == "_":
            regex.append(".")
        else:
            regex.append(re.escape(c))
        i += 1
    return re.compile("^" + "".join(regex) + "$")

def _parse_predicate(ts: _TokenStream) -> Callable[[Dict[str, Any]], bool]:
    field = _parse_identifier(ts)
    tok = ts.peek()

    # IN / NOT IN
    if tok[0] == "WORD" and tok[1] in ("IN", "NOT IN"):
        negate = tok[1] == "NOT IN"
        ts.next()
        values = _parse_value_list(ts)
        values_set = set(values)

        def pred(rec: Dict[str, Any]) -> bool:
            val = rec.get(field, None)
            res = val in values_set
            return (not res) if negate else res

        return pred

    # LIKE / ILIKE
    if tok[0] == "WORD" and tok[1] in ("LIKE", "ILIKE"):
        case_insensitive = tok[1] == "ILIKE"
        ts.next()
        pat_val = _parse_value(ts)
        if not isinstance(pat_val, str):
            raise ValueError("LIKE/ILIKE requires a string pattern")
        regex = _like_to_regex(pat_val)
        if case_insensitive:
            regex = re.compile(regex.pattern, re.IGNORECASE)

        def pred(rec: Dict[str, Any]) -> bool:
            val = rec.get(field, None)
            if val is None:
                return False
            return bool(regex.fullmatch(str(val)))

        return pred

    # Comparison operators
    if tok[0] == "OP":
        op_text = tok[1]
        ts.next()
        right = _parse_value(ts)
        op_map = {
            "=": operator.eq,
            "!=": operator.ne,
            "<>": operator.ne,
            "<": operator.lt,
            "<=": operator.le,
            ">": operator.gt,
            ">=": operator.ge,
        }
        if op_text not in op_map:
            raise ValueError(f"Unsupported operator: {op_text}")
        op_func = op_map[op_text]

        def pred(rec: Dict[str, Any]) -> bool:
            left = rec.get(field, None)
            try:
                return bool(op_func(left, right))
            except Exception:
                return False

        return pred

    raise ValueError("Invalid predicate near: {}".format(tok))

def _parse_unary(ts: _TokenStream) -> Callable[[Dict[str, Any]], bool]:
    if ts.match_word("NOT"):
        inner = _parse_unary(ts)

        def neg(rec: Dict[str, Any]) -> bool:
            return not inner(rec)

        return neg
    if ts.match_type("LPAREN"):
        inner = _parse_expr(ts)
        ts.expect("RPAREN", ")")
        return inner
    return _parse_predicate(ts)

def _parse_and(ts: _TokenStream) -> Callable[[Dict[str, Any]], bool]:
    left = _parse_unary(ts)

    def make_and(a, b):
        return lambda rec: a(rec) and b(rec)

    while ts.match_word("AND"):
        right = _parse_unary(ts)
        left = make_and(left, right)
    return left

def _parse_expr(ts: _TokenStream) -> Callable[[Dict[str, Any]], bool]:
    left = _parse_and(ts)

    def make_or(a, b):
        return lambda rec: a(rec) or b(rec)

    while ts.match_word("OR"):
        right = _parse_and(ts)
        left = make_or(left, right)
    return left

def _compile_where(where_str: str) -> Callable[[Dict[str, Any]], bool]:
    tokens = _tokenize_where(where_str)
    ts = _TokenStream(tokens)
    predicate = _parse_expr(ts)
    # Ensure all tokens consumed
    if ts.peek()[0] != "EOF":
        raise ValueError("Unexpected tokens after WHERE clause")
    return predicate

def _parse_select_fields(select_part: str):
    fields_part = select_part.strip()
    if fields_part == "*":
        return None  # select all
    # Split by commas
    fields = []
    for seg in fields_part.split(","):
        name = seg.strip()
        if not name:
            continue
        # Support optional AS alias; ignore alias for output key names
        m = re.match(r"^([A-Za-z_][A-Za-z0-9_\.]*)(?:\s+AS\s+[A-Za-z_][A-Za-z0-9_\.]*)?$", name, flags=re.IGNORECASE)
        if not m:
            raise ValueError(f"Invalid field in SELECT: {name!r}")
        fields.append(m.group(1))
    if not fields:
        raise ValueError("SELECT clause has no fields")
    return fields

def _parse_order_by(order_part: str):
    items = [item.strip() for item in order_part.split(",") if item.strip()]
    orderings = []
    for item in items:
        parts = item.split()
        if not parts:
            continue
        field = parts[0]
        direction = parts[1].upper() if len(parts) > 1 else "ASC"
        if direction not in ("ASC", "DESC"):
            raise ValueError(f"Invalid ORDER BY direction for {field!r}: {direction!r}")
        orderings.append((field, direction == "ASC"))
    return orderings

def _safe_sort_key(val: Any):
    if val is None:
        return (1, 0)
    # Normalize types for consistent comparisons
    if isinstance(val, bool):
        return (0, int(val))
    if isinstance(val, (int, float)):
        return (0, float(val))
    if isinstance(val, str):
        return (0, val)
    # Fallback to string representation
    return (0, str(val))

def execute_query_cmd(dataset_list: List[Dict[str, Any]], sql_query: str) -> List[Dict[str, Any]]:
    """
    Execute a simple SQL-like query over a list of dictionaries.

    Supported features:
    - SELECT fields or SELECT *
    - WHERE with operators: =, !=, <>, <, <=, >, >=, IN, NOT IN, LIKE, ILIKE
      Logical operators: NOT, AND, OR with parentheses
    - ORDER BY field [ASC|DESC], multiple keys supported

    Raises ValueError on malformed queries or execution errors.
    """
    try:
        if not isinstance(sql_query, str) or not sql_query.strip():
            raise ValueError("sql_query must be a non-empty string")

        # Parse the query into SELECT, FROM, WHERE, ORDER BY
        # FROM part is required syntactically but the table name is ignored.
        m = re.match(
            r"(?is)^\s*SELECT\s+(?P<select>.+?)\s+FROM\s+(?P<table>[A-Za-z_][A-Za-z0-9_\.]*)(?:\s+WHERE\s+(?P<where>.+?))?(?:\s+ORDER\s+BY\s+(?P<order>.+?))?\s*$",
            sql_query,
        )
        if not m:
            raise ValueError("Malformed query: could not parse SELECT/FROM/WHERE/ORDER BY")

        select_part = m.group("select")
        where_part = m.group("where")
        order_part = m.group("order")

        # Compile WHERE predicate if present
        if where_part is not None:
            predicate = _compile_where(where_part)
            filtered = filter_data(list(dataset_list or []), predicate)
        else:
            filtered = [rec for rec in (dataset_list or []) if isinstance(rec, dict)]

        # Apply ORDER BY on filtered data (using source fields)
        if order_part:
            orderings = _parse_order_by(order_part)
            sorted_records = list(filtered)
            # Apply stable sorts from last key to first
            for field, asc in reversed(orderings):
                sorted_records.sort(
                    key=lambda rec, f=field: _safe_sort_key(rec.get(f, None)),
                    reverse=not asc,
                )
        else:
            sorted_records = list(filtered)

        # Apply SELECT
        fields = _parse_select_fields(select_part)
        if fields is None:
            # SELECT * -> return shallow copies
            result = [dict(rec) for rec in sorted_records]
        else:
            result = select_fields(sorted_records, fields)

        return result
    except Exception as e:
        raise ValueError(f"Query execution failed: {e}") from None

import re
import operator
from functools import partial
from typing import Any, Dict, List, Mapping, Sequence, Optional


def extract_fields(
    records: Sequence[Mapping[str, Any]],
    fields: Sequence[str],
    conditions: Optional[Mapping[str, Any]] = None,
) -> List[Dict[str, Any]]:
    """
    Extract a subset of fields from each record in a list of dictionaries, with optional filtering.

    Args:
        records: A sequence of mapping objects (e.g., dicts) representing the dataset.
        fields: A sequence of field names to extract from each record.
        conditions: A mapping of field names to required values. Only records that meet all
            conditions are included. If any condition references a field that does not exist
            in a record, a ValueError is raised.

    Returns:
        A list of dictionaries where each dictionary contains only the specified fields
        present in the corresponding input record. Missing fields are omitted.

    Raises:
        TypeError: If any item in records is not a mapping/dict, or if conditions is not a mapping.
        ValueError: If fields is None, or if a condition references a non-existent field in a record.
    """
    if fields is None:
        raise ValueError("fields must not be None")

    if conditions is not None and not isinstance(conditions, Mapping):
        raise TypeError("conditions must be a mapping/dict if provided")

    # Deduplicate fields while preserving order
    unique_fields = list(dict.fromkeys(fields))

    cond_items = list(conditions.items()) if conditions else []

    result: List[Dict[str, Any]] = []
    for idx, record in enumerate(records):
        if not isinstance(record, Mapping):
            raise TypeError(f"Record at index {idx} is not a mapping/dict: {type(record).__name__}")

        # Apply filtering conditions
        include = True
        for key, expected in cond_items:
            if key not in record:
                raise ValueError(f"Condition references non-existent field '{key}' in record at index {idx}")
            if record[key] != expected:
                include = False
                break
        if not include:
            continue

        filtered = {key: record[key] for key in unique_fields if key in record}
        result.append(filtered)

    return result


def execute_query_cmd(dataset_list: Sequence[Mapping[str, Any]], sql_query: str) -> List[Dict[str, Any]]:
    """
    Execute a simple SQL-like command against a list of dictionaries.

    Supported syntax (FROM is implicit; the dataset is provided via dataset_list):
      SELECT field1, field2, ...
      SELECT *
      [WHERE <predicate> [AND <predicate> ...]]
      [ORDER BY field [ASC|DESC] [, field2 [ASC|DESC] ...]]

    Predicates support:
      - field = value
      - field != value (or <>)
      - field <, <=, >, >= value
      - field IN (value1, value2, ...)
      - field NOT IN (value1, value2, ...)

    Values can be:
      - Numbers (int or float), booleans (true/false), null/none, or quoted strings ('...' or "...").

    Returns:
        List of dictionaries representing the query result (projection happens after filtering and sorting).

    Raises:
        ValueError: If the query is malformed or cannot be processed (e.g., invalid syntax, missing fields in WHERE/ORDER BY).
    """

    if not isinstance(sql_query, str):
        raise ValueError("sql_query must be a string")

    query = sql_query.strip()
    if not query:
        raise ValueError("Empty query")

    # Allow trailing semicolon
    if query.endswith(";"):
        query = query[:-1].rstrip()

    # Parse top-level clauses: SELECT ... [WHERE ...] [ORDER BY ...]
    # WHERE is made non-greedy so ORDER BY (if present) is captured by the last group.
    m = re.match(
        r"^\s*SELECT\s+(?P<select>.*?)\s*(?:WHERE\s+(?P<where>.*?))?\s*(?:ORDER\s+BY\s+(?P<order>.*))?\s*$",
        query,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if not m:
        raise ValueError("Malformed query: expected SELECT [WHERE ...] [ORDER BY ...]")

    select_part = (m.group("select") or "").strip()
    where_part = (m.group("where") or "").strip()
    order_part = (m.group("order") or "").strip()

    if not select_part:
        raise ValueError("Malformed query: missing SELECT list")

    # Parse SELECT fields
    select_all = select_part == "*"
    if not select_all:
        select_fields = [s.strip() for s in select_part.split(",") if s.strip()]
        if not select_fields:
            raise ValueError("Malformed query: empty SELECT list")
        ident_re = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")
        for f in select_fields:
            if not ident_re.fullmatch(f):
                raise ValueError(f"Malformed query: invalid field name in SELECT: {f!r}")
    else:
        select_fields = []

    # Helper functions for parsing WHERE predicates
    def _split_comma_list(s: str) -> List[str]:
        items: List[str] = []
        buf: List[str] = []
        quote: Optional[str] = None
        escape = False
        for ch in s:
            if escape:
                buf.append(ch)
                escape = False
                continue
            if ch == "\\":
                escape = True
                continue
            if quote:
                if ch == quote:
                    quote = None
                else:
                    buf.append(ch)
                continue
            if ch in ("'", '"'):
                quote = ch
                continue
            if ch == "," and not quote:
                items.append("".join(buf).strip())
                buf = []
            else:
                buf.append(ch)
        if quote:
            raise ValueError("Malformed query: unmatched quote in list")
        tail = "".join(buf).strip()
        if tail:
            items.append(tail)
        return items

    def _unescape_quoted(s: str) -> str:
        out: List[str] = []
        i = 0
        while i < len(s):
            ch = s[i]
            if ch == "\\" and i + 1 < len(s):
                i += 1
                out.append(s[i])
            else:
                out.append(ch)
            i += 1
        return "".join(out)

    def _parse_atom(token: str) -> Any:
        t = token.strip()
        if not t:
            raise ValueError("Malformed query: empty value")
        # Quoted string
        if (t[0] == t[-1]) and t[0] in ("'", '"') and len(t) >= 2:
            inner = t[1:-1]
            return _unescape_quoted(inner)
        # Booleans
        tl = t.lower()
        if tl == "true":
            return True
        if tl == "false":
            return False
        if tl in ("null", "none"):
            return None
        # Number (int or float)
        num_match = re.fullmatch(r"[-+]?\d+(?:\.\d+)?", t)
        if num_match:
            if "." in t:
                try:
                    return float(t)
                except ValueError:
                    pass
            else:
                try:
                    return int(t)
                except ValueError:
                    pass
        # Fallback: treat as bare string literal
        return t

    # Build predicate functions
    predicates = []
    if where_part:
        # Split on AND (case-insensitive) not considering quoted content (simplified assumption)
        cond_tokens = re.split(r"\s+AND\s+", where_part, flags=re.IGNORECASE)
        comp_ops = {
            "=": operator.eq,
            "!=": operator.ne,
            "<>": operator.ne,
            "<": operator.lt,
            "<=": operator.le,
            ">": operator.gt,
            ">=": operator.ge,
        }
        for raw in cond_tokens:
            cond = raw.strip()
            if not cond:
                raise ValueError("Malformed query: empty predicate in WHERE")

            # IN or NOT IN
            m_in = re.match(
                r"^(?P<field>[A-Za-z_][A-Za-z0-9_]*)\s+(?P<op>NOT\s+IN|IN)\s*\((?P<vals>.*)\)\s*$",
                cond,
                flags=re.IGNORECASE | re.DOTALL,
            )
            if m_in:
                field = m_in.group("field")
                op_word = m_in.group("op").upper().replace("  ", " ")
                vals_raw = m_in.group("vals")
                items = _split_comma_list(vals_raw)
                if not items:
                    raise ValueError("Malformed query: IN list is empty")
                parsed_vals = [_parse_atom(x) for x in items]

                # Prefer set for performance when possible
                try:
                    values_container = set(parsed_vals)
                    is_set = True
                except TypeError:
                    values_container = list(parsed_vals)
                    is_set = False

                if op_word == "IN":
                    def pred_in(rec: Mapping[str, Any], f=field, cont=values_container, use_set=is_set) -> bool:
                        if f not in rec:
                            raise ValueError(f"WHERE references non-existent field '{f}'")
                        val = rec[f]
                        return (val in cont) if use_set else any(val == v for v in cont)
                    predicates.append(pred_in)
                else:
                    def pred_not_in(rec: Mapping[str, Any], f=field, cont=values_container, use_set=is_set) -> bool:
                        if f not in rec:
                            raise ValueError(f"WHERE references non-existent field '{f}'")
                        val = rec[f]
                        return (val not in cont) if use_set else all(val != v for v in cont)
                    predicates.append(pred_not_in)
                continue

            # Comparisons
            m_cmp = re.match(
                r"^(?P<field>[A-Za-z_][A-Za-z0-9_]*)\s*(?P<op>=|!=|<>|<=|>=|<|>)\s*(?P<value>.+?)\s*$",
                cond,
            )
            if m_cmp:
                field = m_cmp.group("field")
                op_symbol = m_cmp.group("op")
                rhs = _parse_atom(m_cmp.group("value"))
                op_func = comp_ops[op_symbol]

                def make_cmp(f: str, cmp_func, rhs_val: Any):
                    def predicate(rec: Mapping[str, Any]) -> bool:
                        if f not in rec:
                            raise ValueError(f"WHERE references non-existent field '{f}'")
                        try:
                            return cmp_func(rec[f], rhs_val)
                        except Exception as ex:
                            raise ValueError(f"Cannot compare field '{f}' to value {rhs_val!r}: {ex}") from None
                    return predicate

                predicates.append(make_cmp(field, op_func, rhs))
                continue

            # Unsupported predicate
            raise ValueError(f"Malformed WHERE predicate: {cond!r}")

    # Apply filtering
    filtered: List[Mapping[str, Any]] = []
    for idx, rec in enumerate(dataset_list):
        if not isinstance(rec, Mapping):
            raise ValueError(f"Dataset item at index {idx} is not a mapping/dict")
        include = True
        for pred in predicates:
            if not pred(rec):
                include = False
                break
        if include:
            filtered.append(rec)

    # ORDER BY processing
    if order_part:
        order_specs: List[Dict[str, Any]] = []
        for token in [t.strip() for t in order_part.split(",") if t.strip()]:
            m_ord = re.fullmatch(
                r"(?P<field>[A-Za-z_][A-Za-z0-9_]*)(?:\s+(?P<dir>ASC|DESC))?",
                token,
                flags=re.IGNORECASE,
            )
            if not m_ord:
                raise ValueError(f"Malformed ORDER BY spec: {token!r}")
            field = m_ord.group("field")
            direction = (m_ord.group("dir") or "ASC").upper()
            order_specs.append({"field": field, "reverse": direction == "DESC"})

        # Stable sort from last to first key
        records = list(filtered)
        for spec in reversed(order_specs):
            field = spec["field"]
            reverse = spec["reverse"]

            def key_func(rec: Mapping[str, Any], f=field):
                if f not in rec:
                    raise ValueError(f"ORDER BY references non-existent field '{f}'")
                return rec[f]

            try:
                records.sort(key=key_func, reverse=reverse)
            except ValueError:
                # re-raise ValueError (from missing fields) as-is
                raise
            except TypeError as ex:
                raise ValueError(f"ORDER BY on field '{field}' failed due to non-comparable values: {ex}") from None
    else:
        records = list(filtered)

    # Projection (SELECT)
    result: List[Dict[str, Any]] = []
    if select_all:
        for rec in records:
            result.append(dict(rec))
    else:
        for rec in records:
            projected = {k: rec[k] for k in select_fields if k in rec}
            result.append(projected)

    return result

